		template_id: 'blank',
		config: {},
		status: 'running'
	});
}

async function readOneEvent(body: ReadableStream<Uint8Array>): Promise<FeedEntry> {
	const reader = body.getReader();
	const decoder = new TextDecoder();
	let buffer = '';
